   266→      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', minHeight: 0 }}>
   267→        {/* Train sidebar using BlueprintJS Card */}
   268→        <Card
   269→          elevation={1}
   270→          style={{
   271→            width: SIDEBAR_WIDTH,
   272→            borderRadius: 0,
   273→            padding: 0,
   274→            flexShrink: 0,
   275→            display: 'flex',
   276→            flexDirection: 'column',
   277→            overflow: 'hidden',
