   283→              padding: '10px 12px',
   284→              borderBottom: '1px solid #e1e8ed',
   285→              backgroundColor: '#f5f8fa',
   286→              fontWeight: 600,
   287→              fontSize: 13,
   288→            }}
   289→          >
   290→            Trains
   291→          </div>
   292→
   293→          {/* Scrollable train list - synced with canvas panY (BUG-002 fix: overflow auto) */}
   294→          <div
   295→            style={{
   296→              flex: 1,
