     1→/**
     2→ * EntityStore - STATE-ARCH-001 Phase 1
     3→ *
     4→ * High-performance TypedArray-based entity storage using Structure of Arrays (SoA).
     5→ * Optimized for WebGL rendering with zero GC pressure in hot path.
     6→ *
     7→ * Key features:
     8→ * - TypedArrays for numeric data (cache-friendly iteration)
     9→ * - Bulk loading optimized for initial data
    10→ * - Cursor-based access (zero-allocation reads)
    11→ * - Direct mutation (no Proxy overhead)
    12→ *
    13→ * Performance targets:
    14→ * - 100k entities in ~1.7MB
    15→ * - Zero GC during pan/zoom
    16→ * - <1ms for bulk load of 5k entities
    17→ */
    18→
    19→import { DEFAULT_VIEW_CONFIG } from '../data/types';
    20→import type {
    21→  IEntityStore,
    22→  TaskArrays,
    23→  TaskStringData,
    24→  TaskData,
    25→  TaskCursor,
    26→  TaskTypeValue,
    27→  TaskColorValue,
    28→} from './types';
    29→import {
    30→  TASK_TYPE_TO_VALUE,
    31→  VALUE_TO_TASK_TYPE,
    32→  TASK_COLOR_TO_VALUE,
    33→  VALUE_TO_TASK_COLOR,
    34→} from './types';
    35→
    36→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    37→
    38→/**
    39→ * Default initial capacity (will grow if needed)
    40→ */
    41→const DEFAULT_CAPACITY = 10000;
    42→
    43→/**
    44→ * Growth factor when arrays need to be resized
    45→ */
    46→const GROWTH_FACTOR = 1.5;
    47→
    48→/**
    49→ * Create TaskArrays with given capacity
    50→ */
    51→function createArrays(capacity: number): TaskArrays {
    52→  return {
    53→    startDay: new Float32Array(capacity),
    54→    duration: new Float32Array(capacity),
    55→    trainIndex: new Uint16Array(capacity),
    56→    type: new Uint8Array(capacity),
    57→    color: new Uint8Array(capacity),
    58→    hasConflict: new Uint8Array(capacity),
    59→    predecessorIndex: new Int32Array(capacity).fill(-1),
    60→  };
    61→}
    62→
    63→/**
    64→ * Resize arrays to new capacity, preserving existing data
    65→ */
    66→function resizeArrays(
    67→  oldArrays: TaskArrays,
    68→  oldCount: number,
    69→  newCapacity: number
    70→): TaskArrays {
    71→  const newArrays = createArrays(newCapacity);
    72→
    73→  // Copy existing data
    74→  newArrays.startDay.set(oldArrays.startDay.subarray(0, oldCount));
    75→  newArrays.duration.set(oldArrays.duration.subarray(0, oldCount));
    76→  newArrays.trainIndex.set(oldArrays.trainIndex.subarray(0, oldCount));
    77→  newArrays.type.set(oldArrays.type.subarray(0, oldCount));
    78→  newArrays.color.set(oldArrays.color.subarray(0, oldCount));
    79→  newArrays.hasConflict.set(oldArrays.hasConflict.subarray(0, oldCount));
    80→  newArrays.predecessorIndex.set(oldArrays.predecessorIndex.subarray(0, oldCount));
    81→
    82→  return newArrays;
    83→}
    84→
    85→/**
    86→ * TaskCursor implementation - lightweight view into arrays
    87→ */
    88→class TaskCursorImpl implements TaskCursor {
    89→  constructor(
    90→    private readonly store: EntityStore,
    91→    public readonly index: number
    92→  ) {}
    93→
    94→  get id(): string {
    95→    return this.store.strings.ids.get(this.index) ?? '';
    96→  }
    97→
    98→  get startDay(): number {
    99→    return this.store.arrays.startDay[this.index];
   100→  }
   101→
   102→  get duration(): number {
   103→    return this.store.arrays.duration[this.index];
   104→  }
   105→
   106→  get trainIndex(): number {
   107→    return this.store.arrays.trainIndex[this.index];
   108→  }
   109→
   110→  get typeValue(): TaskTypeValue {
   111→    return this.store.arrays.type[this.index] as TaskTypeValue;
   112→  }
   113→
   114→  get type(): string {
   115→    return VALUE_TO_TASK_TYPE[this.typeValue];
   116→  }
   117→
   118→  get colorValue(): TaskColorValue {
   119→    return this.store.arrays.color[this.index] as TaskColorValue;
   120→  }
   121→
   122→  get color(): string {
   123→    return VALUE_TO_TASK_COLOR[this.colorValue];
   124→  }
   125→
   126→  get hasConflict(): boolean {
   127→    return this.store.arrays.hasConflict[this.index] === 1;
   128→  }
   129→
   130→  get predecessorIndex(): number {
   131→    return this.store.arrays.predecessorIndex[this.index];
   132→  }
   133→
   134→  get predecessorId(): string | undefined {
   135→    const predIndex = this.predecessorIndex;
   136→    if (predIndex < 0) return undefined;
   137→    return this.store.strings.ids.get(predIndex);
   138→  }
   139→
   140→  // Computed properties for rendering
   141→  get x(): number {
   142→    return this.startDay * pxPerDay;
   143→  }
   144→
   145→  get y(): number {
   146→    return -this.trainIndex * pxPerTrain - pxPerTrain / 2;
   147→  }
   148→
   149→  get width(): number {
   150→    return this.duration * pxPerDay;
   151→  }
   152→}
   153→
   154→/**
   155→ * EntityStore - High-performance SoA storage for task entities
   156→ */
   157→export class EntityStore implements IEntityStore {
   158→  private _count: number = 0;
   159→  private _capacity: number;
   160→  private _arrays: TaskArrays;
   161→  private _strings: TaskStringData;
   162→
   163→  // Reusable cursor to avoid allocations in hot path
   164→  private _cursor: TaskCursorImpl;
   165→
   166→  constructor(initialCapacity: number = DEFAULT_CAPACITY) {
   167→    this._capacity = initialCapacity;
   168→    this._arrays = createArrays(initialCapacity);
   169→    this._strings = {
   170→      ids: new Map(),
   171→      idToIndex: new Map(),
   172→    };
   173→    this._cursor = new TaskCursorImpl(this, 0);
   174→  }
   175→
   176→  get count(): number {
   177→    return this._count;
   178→  }
   179→
   180→  get capacity(): number {
   181→    return this._capacity;
   182→  }
   183→
   184→  get arrays(): TaskArrays {
   185→    return this._arrays;
   186→  }
   187→
   188→  get strings(): TaskStringData {
   189→    return this._strings;
   190→  }
   191→
   192→  /**
   193→   * Ensure capacity for at least `minCapacity` entities
   194→   */
   195→  private ensureCapacity(minCapacity: number): void {
   196→    if (minCapacity <= this._capacity) return;
   197→
   198→    // Grow by factor or to minCapacity, whichever is larger
   199→    const newCapacity = Math.max(
   200→      Math.ceil(this._capacity * GROWTH_FACTOR),
   201→      minCapacity
   202→    );
   203→
   204→    this._arrays = resizeArrays(this._arrays, this._count, newCapacity);
   205→    this._capacity = newCapacity;
   206→  }
   207→
   208→  /**
   209→   * Load entities from array of task objects (bulk load)
   210→   * Optimized for initial data loading
   211→   */
   212→  load(tasks: TaskData[]): void {
   213→    const startTime = performance.now();
   214→
   215→    // Ensure capacity
   216→    this.ensureCapacity(tasks.length);
   217→
   218→    // First pass: load all data and build ID map
   219→    for (let i = 0; i < tasks.length; i++) {
   220→      const task = tasks[i];
   221→
   222→      this._arrays.startDay[i] = task.startDay;
   223→      this._arrays.duration[i] = task.duration;
   224→      this._arrays.trainIndex[i] = task.trainIndex;
   225→      this._arrays.type[i] = TASK_TYPE_TO_VALUE[task.type];
   226→      this._arrays.color[i] = TASK_COLOR_TO_VALUE[task.color];
   227→      this._arrays.hasConflict[i] = task.hasConflict ? 1 : 0;
   228→      this._arrays.predecessorIndex[i] = -1; // Set in second pass
   229→
   230→      this._strings.ids.set(i, task.id);
   231→      this._strings.idToIndex.set(task.id, i);
   232→    }
   233→
   234→    // Second pass: resolve predecessor IDs to indices
   235→    for (let i = 0; i < tasks.length; i++) {
   236→      const task = tasks[i];
   237→      if (task.predecessorId) {
   238→        const predIndex = this._strings.idToIndex.get(task.predecessorId);
   239→        if (predIndex !== undefined) {
   240→          this._arrays.predecessorIndex[i] = predIndex;
   241→        }
   242→      }
   243→    }
   244→
   245→    this._count = tasks.length;
   246→
   247→    const elapsed = performance.now() - startTime;
   248→    if (import.meta.env.DEV) {
   249→      console.log(`[EntityStore] Loaded ${tasks.length} entities in ${elapsed.toFixed(2)}ms`);
   250→    }
   251→  }
   252→
   253→  /**
   254→   * Get task data by index
   255→   * Returns a cursor that reads directly from arrays
   256→   *
   257→   * IMPORTANT: The returned cursor is reused - do not store references
   258→   */
   259→  get(index: number): TaskCursor {
   260→    if (index < 0 || index >= this._count) {
   261→      throw new RangeError(`Index ${index} out of bounds (count: ${this._count})`);
   262→    }
   263→
   264→    // Reuse cursor object to avoid allocation
   265→    (this._cursor as any).index = index;
   266→    return this._cursor;
   267→  }
   268→
   269→  /**
   270→   * Get task data by ID
   271→   * Returns null if not found
   272→   */
   273→  getById(id: string): TaskCursor | null {
   274→    const index = this._strings.idToIndex.get(id);
   275→    if (index === undefined) return null;
   276→    return this.get(index);
   277→  }
   278→
   279→  /**
   280→   * Get a NEW cursor for the given index
   281→   * Use this when you need to store the cursor reference
   282→   */
   283→  getCursor(index: number): TaskCursor {
   284→    if (index < 0 || index >= this._count) {
   285→      throw new RangeError(`Index ${index} out of bounds (count: ${this._count})`);
   286→    }
   287→    return new TaskCursorImpl(this, index);
   288→  }
   289→
   290→  /**
   291→   * Clear all entities
   292→   */
   293→  clear(): void {
   294→    this._count = 0;
   295→    this._strings.ids.clear();
   296→    this._strings.idToIndex.clear();
   297→    // Note: We don't reallocate arrays - just reset count
   298→  }
   299→
   300→  /**
   301→   * Iterator over all valid entities
   302→   * Yields fresh cursors (safe to store)
   303→   */
   304→  *[Symbol.iterator](): Iterator<TaskCursor> {
   305→    for (let i = 0; i < this._count; i++) {
   306→      yield new TaskCursorImpl(this, i);
   307→    }
   308→  }
   309→
   310→  /**
   311→   * Memory usage estimate in bytes
   312→   */
   313→  getMemoryUsage(): number {
   314→    const arrayBytes =
   315→      this._arrays.startDay.byteLength +
   316→      this._arrays.duration.byteLength +
   317→      this._arrays.trainIndex.byteLength +
   318→      this._arrays.type.byteLength +
   319→      this._arrays.color.byteLength +
   320→      this._arrays.hasConflict.byteLength +
   321→      this._arrays.predecessorIndex.byteLength;
   322→
   323→    // Estimate string storage (rough approximation)
   324→    const avgIdLength = 15; // e.g., "TRAIN-001-2024-5"
   325→    const stringBytes = this._count * avgIdLength * 2; // UTF-16
   326→
   327→    return arrayBytes + stringBytes;
   328→  }
   329→
   330→  /**
   331→   * Log memory usage stats
   332→   */
   333→  logMemoryStats(): void {
   334→    if (!import.meta.env.DEV) return;
   335→
   336→    const bytes = this.getMemoryUsage();
   337→    const kb = bytes / 1024;
   338→    const mb = kb / 1024;
